sql:
SELECT COUNT(DISTINCT patient_id) AS unique_patients_no_allergies
FROM patients
WHERE medical_history LIKE '%no allergies%';

SELECT COUNT(*)
FROM clinical_measurements
WHERE variable_id = 1 AND measurement_value > (SELECT AVG(measurement_value) FROM clinical_measurements WHERE variable_id = 1);

SELECT AVG(SES_score) AS average_SES_score
FROM patients
WHERE consent_form_signed = 1;

SELECT COUNT(*) AS total_intakes
FROM dietary_intake
WHERE intake_date = '2023-05-01';

SELECT patient_name
FROM patients
WHERE age >= 40 AND SES_score > 70;

SELECT patient_name 
FROM patients 
WHERE SES_score = ( 
  SELECT MAX(SES_score) 
  FROM patients
);

SELECT SUM(amount) AS total_artichoke_consumed
FROM dietary_intake
WHERE food_item = 'artichoke';
